class Dog:
    def __init__(self, name, age):
        self.name = name
        self.age = age

rex = Dog("Rex", 3)
print(rex)  # Without __str__: ugly memory address

class Dog:
    def __init__(self, name, age):
        self.name = name
        self.age = age

    def __str__(self):
        return f"{self.name} (age {self.age})"

    def __repr__(self):
        return f"Dog('{self.name}', {self.age})"

rex = Dog("Rex", 3)
print(rex)     # uses __str__
print(repr(rex)) # uses __repr__

class Playlist:
    def __init__(self, name):
        self.name = name
        self.songs = []

    def add(self, song):
        self.songs.append(song)

    def __len__(self):
        return len(self.songs)

    def __eq__(self, other):
        return self.name == other.name

p1 = Playlist("Chill")
p1.add("Song A")
p1.add("Song B")
print(len(p1))  # uses __len__

p2 = Playlist("Chill")
print(p1 == p2)  # uses __eq__ — True (same name)

