exercises.solution:
class ShoppingCart:
    def __init__(self):
        self.items = []

    def add_item(self, item):
        self.items.append(item)

    def __len__(self):
        return len(self.items)

cart = ShoppingCart()
cart.add_item("apple")
cart.add_item("bread")
cart.add_item("milk")
print(len(cart))
